import React from 'react';
import './AnonymousNotes.css';

const AnonymousNotes = () => {
  const notes = [
    {
      id: 1,
      user: 'User123',
      message: 'Hi, new anything?',
      time: '2 min ago'
    },
    {
      id: 2,
      user: 'Student_456',
      message: 'Finding it hard to math sometimes.',
      time: '5 min ago'
    },
    {
      id: 3,
      user: 'Anonymous',
      message: 'Feeling you after the breakup. Need someone to talk to...',
      time: '10 min ago'
    }
  ];

  return (
    <div className="anonymous-notes">
      <div className="notes-header">
        <h3>Among notes</h3>
        <button className="menu-btn">≡</button>
      </div>
      
      <div className="notes-search">
        <input 
          type="text" 
          placeholder="Type a topic..." 
          className="search-input"
        />
      </div>

      <div className="notes-list">
        {notes.map((note) => (
          <div key={note.id} className="note-item">
            <div className="note-user">
              <span className="user-avatar">👤</span>
              <span className="username">{note.user}</span>
              <span className="note-arrow">›</span>
            </div>
            <div className="note-message">{note.message}</div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default AnonymousNotes;
